// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // Weather icon helper function
  const getWeatherIcon = (condition: string): string => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
    if (lowerCondition.includes('cloudy') || lowerCondition.includes('cloud')) return '☁️';
    if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
    if (lowerCondition.includes('snowy') || lowerCondition.includes('snow')) return '❄️';
    if (lowerCondition.includes('stormy') || lowerCondition.includes('storm')) return '⛈️';
    if (lowerCondition.includes('windy') || lowerCondition.includes('wind')) return '💨';
    if (lowerCondition.includes('foggy') || lowerCondition.includes('fog')) return '🌫️';
    return '🌤️'; // default
  };

  const weatherIcon = getWeatherIcon(props.condition);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main Weather Card */}
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* City and Condition Header */}
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Row gap="var(--ggui-spacing-3)" align="center">
                <Icon name={weatherIcon} size={48} color="var(--ggui-color-primary-600)" />
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
              </Row>
            </Stack>

            <Divider orientation="horizontal" margin="var(--ggui-spacing-3)" color="var(--ggui-color-outlineVariant)" />

            {/* Temperature Display */}
            <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)">
              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Text variant="caption" color="var(--ggui-color-primary-700)">Current Temperature</Text>
                <Text variant="body" size="2xl" weight="bold" color="var(--ggui-color-primary-900)">{props.temperature}°{props.unit || 'C'}</Text>
              </Stack>
            </Box>

            {/* Humidity and Wind Speed */}
            <Row gap="var(--ggui-spacing-4)" justify="between">
              <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="droplet" size={20} color="var(--ggui-color-primary-600)" />
                  <Stack gap="var(--ggui-spacing-1)" align="center">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                    <Text variant="label" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                  </Stack>
                </Stack>
              </Box>

              <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="wind" size={20} color="var(--ggui-color-primary-600)" />
                  <Stack gap="var(--ggui-spacing-1)" align="center">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                    <Text variant="label" color="var(--ggui-color-onSurface)">{props.windSpeed} mph</Text>
                  </Stack>
                </Stack>
              </Box>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        <Stack gap="var(--ggui-spacing-3)">
          <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
          {props.forecast && props.forecast.length > 0 ? (
            <Row gap="var(--ggui-spacing-2)" wrap>
              {props.forecast.map((day, index) => (
                <Card
                  key={index}
                  padding="var(--ggui-spacing-3)"
                  shadow="sm"
                  radius="md"
                  border={true}
                  style={{ flex: '1 1 120px', minWidth: '100px' }}
                >
                  <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                    <Text variant="label" color="var(--ggui-color-onSurface)" align="center">
                      {day.day || `Day ${index + 1}`}
                    </Text>
                    <Icon name={day.icon || '🌤️'} size={28} />
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      <Row gap="var(--ggui-spacing-2)" justify="center">
                        <Text variant="caption" color="var(--ggui-color-onSurface)" weight="semibold">
                          {day.high ?? 'N/A'}°{props.unit || 'C'}
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {day.low ?? 'N/A'}°{props.unit || 'C'}
                        </Text>
                      </Row>
                    </Stack>
                  </Stack>
                </Card>
              ))}
            </Row>
          ) : (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">No forecast data available</Text>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

