import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // Wire hooks
  const submit = useAction<ActionSubmitPayload>('submit');

  // State for form steps
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Email validation regex
  const validateEmail = useCallback((email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }, []);

  // Validate name (required, non-empty) with real-time feedback
  const validateName = useCallback(() => {
    if (!name.trim()) {
      setNameError('Name is required');
      return false;
    }
    setNameError('');
    return true;
  }, [name]);

  // Validate email (required, valid format) with real-time feedback
  const validateEmailField = useCallback(() => {
    if (!email.trim()) {
      setEmailError('Email is required');
      return false;
    }
    if (!validateEmail(email)) {
      setEmailError('Please enter a valid email address');
      return false;
    }
    setEmailError('');
    return true;
  }, [email, validateEmail]);

  // Real-time validation for Step 1
  // Real-time validation for Step 1 on every keystroke
  useEffect(() => {
    if (currentStep === 1) {
      if (name.trim() !== '') {
        validateName();
      } else {
        setNameError('');
      }
    }
  }, [name, currentStep, validateName]);

  useEffect(() => {
    if (currentStep === 1) {
      if (email.trim() !== '') {
        validateEmailField();
      } else {
        setEmailError('');
      }
    }
  }, [email, currentStep, validateEmailField]);

  // Check if step 1 is valid (must validate to enable Next)
  const isStep1Valid = useMemo(() => {
    return name.trim() !== '' && validateEmail(email);
  }, [name, email, validateEmail]);

  // Check if step 2 is valid (satisfaction selected)
  const isStep2Valid = useMemo(() => {
    return satisfaction !== '';
  }, [satisfaction]);

  // Check if step 3 is valid (at least one feature selected)
  const isStep3Valid = useMemo(() => {
    return features.length > 0;
  }, [features]);

  // Check if all steps complete
  const isComplete = name.trim() && validateEmail(email) && satisfaction && features.length > 0;

  // Handle next step with validation
  const handleNext = useCallback(() => {
    if (currentStep === 1 && !(name.trim() !== '' && validateEmail(email))) {
      return;
    }
    if (currentStep === 2 && satisfaction === '') {
      return;
    }
    if (currentStep === 3 && features.length === 0) {
      return;
    }
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    } else if (currentStep === 4) {
      setCurrentStep(5);
    }
  }, [currentStep, name, email, satisfaction, features, validateEmail]);

  // Handle back step
  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  // Handle submit
  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim(),
    });
  }, [name, email, satisfaction, features, comments, submit]);

  // Handle feature toggle
  const toggleFeature = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  }, []);

  // Render step 1: Name and Email
  const renderStep1 = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <Input
        label="Name"
        placeholder="Enter your name"
        value={name}
        onChange={setName}
        required
        error={nameError}
      />
      <Input
        label="Email"
        type="email"
        placeholder="your.email@example.com"
        value={email}
        onChange={setEmail}
        required
        error={emailError}
      />
    </Stack>
  );

  // Render step 2: Satisfaction Rating
  const renderStep2 = () => {
    const radioOptions = props.satisfactionLabels.map((label, index) => ({
      value: String(index + 1),
      label: `${index + 1} - ${label}`,
    }));

    return (
      <RadioGroup
        label="How satisfied are you with our service?"
        value={satisfaction}
        onChange={setSatisfaction}
        options={radioOptions}
        direction="vertical"
      />
    );
  };

  // Render step 3: Feature Interests
  const renderStep3 = () => (
    <Stack gap="var(--ggui-spacing-3)" align="stretch">
      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
        Which features are you interested in? <Text variant="label" color="var(--ggui-color-error-500)" is="span">*</Text>
      </Text>
      {features.length === 0 && currentStep === 3 && (
        <Text variant="caption" color="var(--ggui-color-error-500)">
          Please select at least one feature
        </Text>
      )}
      <Stack gap="var(--ggui-spacing-2)" align="stretch">
        {props.featureOptions.map((feature) => (
          <Checkbox
            key={feature}
            label={feature}
            checked={features.includes(feature)}
            onChange={() => toggleFeature(feature)}
          />
        ))}
      </Stack>
    </Stack>
  );

  // Render step 4: Comments with character counter
  const renderStep4 = () => (
    <Stack gap="var(--ggui-spacing-3)" align="stretch">
      <TextArea
        label="Additional Comments"
        placeholder="Please share any additional feedback or comments (optional)..."
        value={comments}
        onChange={setComments}
        rows={6}
        maxLength={500}
        showCount
      />
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="right">
        {comments.length} / 500 characters
      </Text>
    </Stack>
  );

  // Render step 5: Review
  const renderReview = () => (
    <Stack gap="var(--ggui-spacing-4)" align="stretch">
      <Card padding="var(--ggui-spacing-4)" shadow="md">
        <Stack gap="var(--ggui-spacing-3)" align="stretch">
          <Heading level={4}>Your Responses</Heading>
          <Divider />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Name
            </Text>
            <Text>{name}</Text>
          </Box>
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Email
            </Text>
            <Text>{email}</Text>
          </Box>
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Satisfaction Rating
            </Text>
            <Text>
              {satisfaction && props.satisfactionLabels[Math.max(0, Math.min(parseInt(satisfaction, 10) - 1, props.satisfactionLabels.length - 1))]} (Rating: {satisfaction})
            </Text>
          </Box>
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Interested Features
            </Text>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" wrap>
              {features.map((feature) => (
                <Badge key={feature} variant="primary" size="sm">
                  {feature}
                </Badge>
              ))}
            </Stack>
          </Box>
          {comments && (
            <Box>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                Comments
              </Text>
              <Text variant="bodySmall">{comments}</Text>
            </Box>
          )}
        </Stack>
      </Card>
    </Stack>
  );

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)" align="stretch">
           <Heading level={1}>Survey Form</Heading>
           <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
             Step {currentStep === 5 ? '4 (Review)' : currentStep} of 4
           </Text>
           <Progress
             value={currentStep === 5 ? 4 : currentStep}
             max={4}
             variant="default"
             size="md"
           />
         </Stack>

         {/* Form Content */}
         <Card padding="var(--ggui-spacing-6)" shadow="md">
           <Stack gap="var(--ggui-spacing-4)" align="stretch">
             {currentStep === 1 && renderStep1()}
             {currentStep === 2 && renderStep2()}
             {currentStep === 3 && renderStep3()}
             {currentStep === 4 && renderStep4()}
             {currentStep === 5 && renderReview()}
           </Stack>
         </Card>

         {/* Navigation */}
         <Row gap="var(--ggui-spacing-3)" justify="between">
           <Button
             variant="ghost"
             onClick={handleBack}
             disabled={currentStep === 1}
           >
             Back
           </Button>
           <Spacer size="flex" />
           {currentStep < 5 && currentStep < 4 && (
             <Button
               variant="primary"
               onClick={handleNext}
               disabled={
                 (currentStep === 1 && !isStep1Valid) ||
                 (currentStep === 2 && !isStep2Valid) ||
                 (currentStep === 3 && !isStep3Valid)
               }
             >
               Next
             </Button>
           )}
           {currentStep === 4 && (
             <Button
               variant="primary"
               onClick={handleNext}
             >
               Review
             </Button>
           )}
           {currentStep === 5 && (
             <Button
               variant="primary"
               onClick={handleSubmit}
             >
               Submit
             </Button>
           )}
         </Row>
       </Stack>
     </Container>
    </Container>
  );
}

