                            <Stack gap="var(--ggui-spacing-2)" align="stretch">
                              <Input
                                label="Task title"
                                value={editingTitle}
                                onChange={setEditingTitle}
                                size="sm"
                                placeholder="Enter task title"
                              />
                              <Row gap="var(--ggui-spacing-2)">
                                <Button
                                  variant="primary"
                                  size="xs"
                                  onClick={() => handleSaveEdit(task.id)}
                                  fullWidth
                                >
                                  Save
                                </Button>
                                <Button
                                  variant="ghost"
                                  size="xs"
                                  onClick={() => {
                                    setEditingTaskId(null);
