                                  Cancel
                                </Button>
                              </Row>
                            </Stack>
                          ) : (
                            <Row gap="var(--ggui-spacing-2)" align="center">
                              <Text
                                is="span"
                                as={Clickable}
                                onDoubleClick={() => handleEditTask(task.id)}
                                style={{ cursor: 'text', flex: 1 }}
                              >
                                {task.title}
                              </Text>
                              <Button
                                variant="ghost"
                                size="xs"
                                onClick={() => handleEditTask(task.id)}
