                            </Row>
                          )}

                          {/* Priority Badge */}
                          {task.priority && (
                            <Row gap="var(--ggui-spacing-2)" align="center">
                              <Badge
                                variant={getPriorityBadgeVariant(task.priority)}
                                size="sm"
                              >
                                {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                              </Badge>
                            </Row>
                          )}

                          {/* Task Meta (Assignee + Due Date) */}
                          <Row gap="var(--ggui-spacing-2)" align="center">
                            {task.assignee && (
                              <Avatar
                                name={task.assignee}
                                size="sm"
                              />
                            )}
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                                {new Date(task.dueDate).toLocaleDateString(undefined, {
                                  month: 'short',
