                            )}
                          </Row>

                          {/* Move Button / Dropdown */}
                          {props.columns.length > 1 && (
                            <Dropdown
                              trigger={
                                <Button
                                  variant="outline"
                                  size="sm"
                                  fullWidth
                                >
                                  <Icon name="arrow-right" size={14} /> Move
                                </Button>
                              }
                              options={props.columns
                                .filter(c => c.id !== columnId)
                                .map(c => ({
                                  value: c.id || '',
                                  label: c.name || '',
                                }))}
                              value=""
                              onChange={(toColumnId) =>
                                handleMoveTask(task.id, columnId, toColumnId)
                              }
                              placement="bottom-end"
                            />
                          )}
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {/* Add Task Form */}
                  <Card
                    padding="var(--ggui-spacing-3)"
                    shadow="none"
                    border={false}
                    background="var(--ggui-color-surface)"
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      {!newTaskForm[columnId] ? (
                        <Button
                          variant="ghost"
                          size="sm"
                          fullWidth
                          onClick={() =>
                            setNewTaskForm(prev => ({
                              ...prev,
                              [columnId]: { title: '', priority: 'medium' },
                            }))
                          }
                        >
                          <Icon name="plus" size={16} /> Add Task
                        </Button>
                      ) : (
                        <>
                          <Input
                            label="New task title"
                            placeholder="Enter task title"
                            value={newTaskForm[columnId]?.title || ''}
                            onChange={(value) =>
                              setNewTaskForm(prev => ({
                                ...prev,
                                [columnId]: { ...prev[columnId]!, title: value },
                              }))
                            }
                            size="sm"
                          />
                          <Select
                            label="Priority"
                            value={newTaskForm[columnId]?.priority || 'medium'}
                            onChange={(value) =>
                              setNewTaskForm(prev => ({
                                ...prev,
                                [columnId]: {
                                  ...prev[columnId]!,
                                  priority: value as 'low' | 'medium' | 'high',
                                },
                              }))
                            }
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
