                          <Row gap="var(--ggui-spacing-2)">
                            <Button
                              variant="primary"
                              size="sm"
                              fullWidth
                              onClick={() => handleAddTask(columnId)}
                            >
                              Create
                            </Button>
                            <Button
                              variant="ghost"
                              size="sm"
                              fullWidth
                              onClick={() =>
                                setNewTaskForm(prev => {
                                  const updated = { ...prev };
                                  delete updated[columnId];
                                  return updated;
                                })
                              }
                            >
                              Cancel
                            </Button>
                          </Row>
                        </>
                      )}
                    </Stack>
                  </Card>
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

