interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

// Color map for element categories
const CATEGORY_COLORS: Record<string, { bg: string; text: string; border: string }> = {
  'alkali metal': { bg: 'var(--ggui-color-primary-100)', text: 'var(--ggui-color-primary-900)', border: 'var(--ggui-color-primary-300)' },
  'alkaline earth metal': { bg: 'var(--ggui-color-warning-100)', text: 'var(--ggui-color-warning-900)', border: 'var(--ggui-color-warning-300)' },
  'transition metal': { bg: 'var(--ggui-color-info-100)', text: 'var(--ggui-color-info-900)', border: 'var(--ggui-color-info-300)' },
  'post-transition metal': { bg: 'var(--ggui-color-primary-50)', text: 'var(--ggui-color-primary-800)', border: 'var(--ggui-color-primary-200)' },
  'metalloid': { bg: 'var(--ggui-color-warning-50)', text: 'var(--ggui-color-warning-800)', border: 'var(--ggui-color-warning-200)' },
  'nonmetal': { bg: 'var(--ggui-color-success-100)', text: 'var(--ggui-color-success-900)', border: 'var(--ggui-color-success-300)' },
  'halogen': { bg: 'var(--ggui-color-error-100)', text: 'var(--ggui-color-error-900)', border: 'var(--ggui-color-error-300)' },
  'noble gas': { bg: 'var(--ggui-color-info-50)', text: 'var(--ggui-color-info-800)', border: 'var(--ggui-color-info-200)' },
  'default': { bg: 'var(--ggui-color-surface)', text: 'var(--ggui-color-onSurface)', border: 'var(--ggui-color-outline)' },
};

export default function Component(props: Props) {
  // State
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        (el.name?.toLowerCase().includes(query) || false) ||
        (el.symbol?.toLowerCase().includes(query) || false)
    );
  }, [searchQuery, props.elements]);

  // Get unique categories and their counts for legend
  const categories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  // Get color for a category
  const getCategoryColor = (category?: string) => {
    if (!category) return CATEGORY_COLORS['default'];
    return CATEGORY_COLORS[category] || CATEGORY_COLORS['default'];
  };
  return (
    <Stack gap="var(--ggui-spacing-6)" direction="vertical">
      {/* Search input */}
      <SearchField
        value={searchQuery}
        onChange={setSearchQuery}
        placeholder="Search by name or symbol (e.g., 'Hydrogen', 'H')"
        size="md"
      />

      {/* Legend */}
      <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)">
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ marginBottom: 'var(--ggui-spacing-2)' }}>
          Legend
        </Text>
        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
          {categories.map((cat) => {
            const colors = getCategoryColor(cat);
            return (
              <Row key={cat} gap="var(--ggui-spacing-2)" align="center">
                <Box
                  style={{
                    width: '12px',
                    height: '12px',
                    borderRadius: 'var(--ggui-shape-radius-sm)',
                    background: colors.bg,
                    border: `1px solid ${colors.border}`,
                  }}
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {cat}
                </Text>
              </Row>
            );
          })}
        </Stack>
      </Box>

      {/* Periodic table grid */}
      <Box
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, 1fr)',
          gap: 'var(--ggui-spacing-2)',
          padding: 'var(--ggui-spacing-4)',
          background: 'var(--ggui-color-surface)',
          borderRadius: 'var(--ggui-shape-radius-lg)',
          border: '1px solid var(--ggui-color-outline)',
        }}
      >
        {filteredElements.map((el) => {
          if (!el.row || !el.col) return null;
          const colors = getCategoryColor(el.category);
          const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

          return (
            <Box
              key={el.atomicNumber}
              as={Clickable}
              onClick={() => setSelectedElement(el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                background: colors.bg,
                border: `2px solid ${isSelected ? 'var(--ggui-color-primary-600)' : colors.border}`,
                borderRadius: 'var(--ggui-shape-radius-md)',
                padding: 'var(--ggui-spacing-2)',
                cursor: 'pointer',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
                alignItems: 'center',
                minHeight: '80px',
                transition: 'all 200ms ease-in-out',
                boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'var(--ggui-shape-shadow-sm)',
              }}
              hoverStyle={{
                transform: 'scale(1.05)',
                boxShadow: 'var(--ggui-shape-shadow-lg)',
              }}
            >
              {/* Atomic number (top-left) */}
              <Text
                variant="caption"
                color={colors.text}
                style={{
                  position: 'absolute',
                  top: 'var(--ggui-spacing-1)',
                  left: 'var(--ggui-spacing-1)',
                  fontWeight: 'var(--ggui-font-weight-semibold)',
                }}
              >
                {el.atomicNumber}
              </Text>

              {/* Symbol (large, centered) */}
              <Text
                variant="body"
                color={colors.text}
                align="center"
                style={{
                  fontSize: 'var(--ggui-font-size-2xl)',
                  fontWeight: 'var(--ggui-font-weight-bold)',
                  lineHeight: '1',
                }}
              >
                {el.symbol}
              </Text>

              {/* Name (small) */}
              <Text
                variant="caption"
                color={colors.text}
                align="center"
                style={{
                  marginTop: 'var(--ggui-spacing-1)',
                }}
              >
                {el.name}
              </Text>
            </Box>
          );
        })}
      </Box>

      {/* Detail panel */}
      {selectedElement && (
        <Card shadow="md" padding="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-4)" direction="vertical">
            <Row gap="var(--ggui-spacing-4)" justify="between" align="start">
              <Stack gap="var(--ggui-spacing-2)" direction="vertical">
                <Heading level={2}>{selectedElement.name}</Heading>
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Text variant="bodyLarge" style={{ fontWeight: 'var(--ggui-font-weight-bold)' }}>
                    {selectedElement.symbol}
                  </Text>
                  {selectedElement.category && (
                    <Badge variant="primary" size="sm">
                      {selectedElement.category}
                    </Badge>
                  )}
                </Row>
              </Stack>
              <Button variant="ghost" onClick={() => setSelectedElement(null)}>
                Close
              </Button>
            </Row>

            <Divider margin="var(--ggui-spacing-3)" />

            <Stack gap="var(--ggui-spacing-3)" direction="vertical">
              <Row gap="var(--ggui-spacing-4)" wrap>
                <Stack gap="var(--ggui-spacing-1)" direction="vertical">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Atomic Number
                  </Text>
                  <Text variant="bodyLarge" style={{ fontWeight: 'var(--ggui-font-weight-semibold)' }}>
                    {selectedElement.atomicNumber}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)" direction="vertical">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Atomic Weight
                  </Text>
                  <Text variant="bodyLarge" style={{ fontWeight: 'var(--ggui-font-weight-semibold)' }}>
                    {selectedElement.atomicWeight?.toFixed(3)}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)" direction="vertical">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Position
                  </Text>
                  <Text variant="bodyLarge" style={{ fontWeight: 'var(--ggui-font-weight-semibold)' }}>
                    Row {selectedElement.row}, Col {selectedElement.col}
                  </Text>
                </Stack>
              </Row>
            </Stack>
          </Stack>
        </Card>
      )}

      {/* Empty state for search */}
      {filteredElements.length === 0 && (
        <Box padding="var(--ggui-spacing-12)" style={{ textAlign: 'center' }}>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            No elements found matching "{searchQuery}". Try searching by element name or symbol.
          </Text>
        </Box>
      )}
    </Stack>
  );
}

