                          {renderStars(review.rating)}
                        </Row>
                      </Row>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {review.date ? new Date(review.date).toLocaleDateString() : 'N/A'}
                      </Text>
                    </Row>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                      {review.text || review.content || 'No review text'}
                    </Text>
                  </Stack>
                </Card>
              ))}
            </Stack>
          ) : (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              No reviews available
            </Text>
          )}
        </Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Top Section: Image, Title, Price, Rating, Stock */}
        <Stack gap="var(--ggui-spacing-6)" direction="horizontal" align="start">
          {/* Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-50)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-8)"
            style={{ minWidth: '300px', minHeight: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack gap="var(--ggui-spacing-3)" align="center" justify="center">
              <Icon name="image" size={48} color="var(--ggui-color-primary-600)" />
              <Text variant="body" color="var(--ggui-color-primary-700)" align="center">
                {props.product.name || 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
            {/* Title */}
            <Heading level={1} color="var(--ggui-color-onSurface)">
              {props.product.name || 'Product'}
            </Heading>

            {/* Price and Rating */}
            <Row gap="var(--ggui-spacing-4)" align="center">
              <Text size="2xl" weight="bold" color="var(--ggui-color-primary-600)">
                {formattedPrice}
              </Text>
              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" />
              <Row gap="var(--ggui-spacing-1)" align="center">
                <Row gap="var(--ggui-spacing-1)">
                  {renderStars(props.product.rating)}
                </Row>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  ({props.product.reviewCount || 0} reviews)
                </Text>
              </Row>
            </Row>

            {/* Stock Status Badge */}
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Badge variant={badgeVariant} size="md">
                {stockStatus}
              </Badge>
              {props.product.stock !== undefined && (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {props.product.stock} units available
                </Text>
              )}
            </Row>
          </Stack>
        </Stack>

        {/* Middle Section: Tabs */}
        <Stack gap="var(--ggui-spacing-4)">
          <Tabs
            items={tabItems}
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            size="md"
          />
        </Stack>

        {/* Bottom Section: Quantity Selector and Add to Cart */}
        <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center">
          {/* Quantity Selector */}
          <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Quantity:
            </Text>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Button
                variant="outline"
                size="sm"
                onClick={handleDecrement}
                disabled={quantity === 1}
              >
                −
              </Button>
              <Box
                padding="var(--ggui-spacing-2) var(--ggui-spacing-4)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-md)"
                style={{ minWidth: '50px', textAlign: 'center' }}
              >
                <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                  {quantity}
                </Text>
              </Box>
              <Button
                variant="outline"
                size="sm"
                onClick={handleIncrement}
                disabled={quantity >= (props.product.stock || 1) || isOutOfStock}
              >
                +
              </Button>
            </Row>
          </Stack>

          <Spacer size="flex" />

          {/* Add to Cart Button */}
          <Button
            variant="primary"
            size="lg"
            onClick={handleAddToCart}
            disabled={isOutOfStock}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}
}

