// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State management
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const [typingIndicator, setTypingIndicator] = useState<{ sender?: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages(prev => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest?.active === false) {
      setTypingIndicator(null);
    } else if (typing.latest?.active === true) {
      setTypingIndicator({ sender: typing.latest.sender });
    }
  }, [typing.latest]);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages, typingIndicator]);

  // Handle sending a message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      // Optionally add sent message to local state immediately for better UX
      setAllMessages(prev => [...prev, { sender: props.currentUser, text: inputValue, timestamp }]);
      setInputValue('');
    }
  }, [inputValue, props.currentUser, sendMessage]);

  // Handle Enter key to send
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Format timestamp for display
  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
  };

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      if (groups.length > 0 && groups[groups.length - 1].sender === msg.sender) {
        groups[groups.length - 1].messages.push(msg);
      } else {
        groups.push({
          sender: msg.sender,
          messages: [msg],
        });
      }
    });

    return groups;
  }, [allMessages]);

  const isCurrentUser = (sender?: string) => sender === props.currentUser;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" style={{ display: 'flex', flexDirection: 'column', height: '600px' }}>
        {/* Header */}
        <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-4)" style={{ marginBottom: 'var(--ggui-spacing-4)', paddingBottom: 'var(--ggui-spacing-4)', borderBottom: '1px solid var(--ggui-color-outline)' }}>
          <Stack direction="vertical" gap="var(--ggui-spacing-1)" align="start">
            <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
          </Stack>
          <Badge variant="info" size="md">{props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}</Badge>
        </Stack>

        {/* Messages List */}
        <Stack direction="vertical" gap="var(--ggui-spacing-3)" style={{ flex: 1, overflowY: 'auto', paddingRight: 'var(--ggui-spacing-3)' }} align="stretch">
          {groupedMessages.length === 0 ? (
            <Text color="var(--ggui-color-onSurfaceVariant)" align="center" style={{ marginTop: 'var(--ggui-spacing-8)' }}>
              No messages yet. Start the conversation!
            </Text>
          ) : (
            groupedMessages.map((group, groupIdx) => {
              const isOwn = isCurrentUser(group.sender);
              return (
                <Stack
                  key={groupIdx}
                  direction="vertical"
                  gap="var(--ggui-spacing-1)"
                  align={isOwn ? 'end' : 'start'}
                  style={{ maxWidth: '70%', alignSelf: isOwn ? 'flex-end' : 'flex-start' }}
                >
                  {group.messages.map((msg, msgIdx) => (
                    <Stack key={msgIdx} direction="vertical" gap="var(--ggui-spacing-1)" align={isOwn ? 'end' : 'start'}> 
                      {!isOwn && (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ marginLeft: 'var(--ggui-spacing-2)', marginBottom: 'var(--ggui-spacing-1)' }}>{group.sender || 'Unknown'}</Text>
                      )}
                      <Box
                        padding="var(--ggui-spacing-3)"
                        background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                        borderRadius="var(--ggui-shape-radius-lg)"
                        style={{
                          wordWrap: 'break-word',
                          wordBreak: 'break-word',
                        }}
                      >
                        <Text
                          color={isOwn ? 'white' : 'var(--ggui-color-onSurface)'}
                          variant="body"
                        >
                          {msg.text}
                        </Text>
                        <Text
                          color={isOwn ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                          variant="caption"
                          style={{ marginTop: 'var(--ggui-spacing-1)' }}
                        >
                          {formatTime(msg.timestamp)}
                        </Text>
                      </Box>
                    </Stack>
                  ))}
                </Stack>
              );
            })
          )}

          {/* Typing Indicator */}
          {typingIndicator && (
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
              <Text color="var(--ggui-color-onSurfaceVariant)" variant="caption">
                {typingIndicator.sender || 'Someone'} is typing
              </Text>
              <Box style={{ display: 'flex', gap: '4px' }}>
                <Box
                  style={{
                    width: '8px',
                    height: '8px',
                    borderRadius: '50%',
                    background: 'var(--ggui-color-primary-600)',
                    animation: 'pulse 1.4s infinite',
                  }}
                />
                <Box
                  style={{
                    width: '8px',
                    height: '8px',
                    borderRadius: '50%',
                    background: 'var(--ggui-color-primary-600)',
                    animation: 'pulse 1.4s infinite 0.2s',
                  }}
                />
                <Box
                  style={{
                    width: '8px',
                    height: '8px',
                    borderRadius: '50%',
                    background: 'var(--ggui-color-primary-600)',
                    animation: 'pulse 1.4s infinite 0.4s',
                  }}
                />
              </Box>
            </Stack>
          )}

          {/* Anchor for auto-scroll */}
          <div ref={messagesEndRef} />
        </Stack>

        {/* Input Area */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="end" style={{ marginTop: 'var(--ggui-spacing-4)', paddingTop: 'var(--ggui-spacing-4)', borderTop: '1px solid var(--ggui-color-outline)' }}>
          <TextArea
            label="Message"
            placeholder="Type your message..."
            value={inputValue}
            onChange={setInputValue}
            rows={2}
            style={{ flex: 1 }}
            onKeyDown={handleKeyDown}
          />
          <Button
            variant="primary"
            size="md"
            onClick={handleSendMessage}
            disabled={!inputValue.trim()}
          >
            Send
          </Button>
        </Stack>
      </Card>
      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 0.3; }
          50% { opacity: 1; }
        }
      `}</style>
    </Container>
  );
}

