import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

<style>{`
  @keyframes ggui-flash-highlight {
    0% { background-color: transparent; }
    10% { background-color: var(--ggui-color-success-100); }
    90% { background-color: var(--ggui-color-success-100); }
    100% { background-color: transparent; }
  }
  .stock-grid {
    display: grid;
    gap: var(--ggui-spacing-4);
    grid-template-columns: repeat(3, 1fr);
  }
  @media (max-width: 768px) {
    .stock-grid {
      grid-template-columns: repeat(1, 1fr);
    }
  }
  .stock-card-flash {
    animation: ggui-flash-highlight 0.9s ease-in-out;
  }
`}</style>

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for displayed stocks — merge with live updates
  const [displayedStocks, setDisplayedStocks] = useState<typeof props.stocks>([]);
  const [lastUpdatedTime, setLastUpdatedTime] = useState<string>('');
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());
  const updateTimerRef = useRef<NodeJS.Timeout | null>(null);

  // Initialize displayed stocks from props
  useEffect(() => {
    setDisplayedStocks(props.stocks || []);
  }, [props.stocks]);

  // Update last updated timestamp every second
  useEffect(() => {
    const updateTime = () => {
      setLastUpdatedTime(new Date().toLocaleTimeString());
    };
    updateTime();
    updateTimerRef.current = setInterval(updateTime, 1000);
    return () => {
      if (updateTimerRef.current) clearInterval(updateTimerRef.current);
    };
  }, []);

  // Merge live price updates into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setDisplayedStocks((prev) => {
        const updated = prev.map((stock) => {
          if (stock.symbol === update.symbol) {
            return {
              ...stock,
              price: update.price ?? stock.price,
              change: update.change ?? stock.change,
              changePercent: update.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
        return updated;
      });

      // Trigger flash animation
      if (update.symbol) {
        setFlashingSymbols((prev) => new Set(prev).add(update.symbol));
        setTimeout(() => {
          setFlashingSymbols((prev) => {
            const next = new Set(prev);
            next.delete(update.symbol!);
            return next;
          });
        }, 900);
      }
    }
  }, [priceUpdate.latest]);

  // Format price with 2 decimals
  const formatPrice = (price?: number): string => {
    if (price === undefined || price === null) return 'N/A';
    return price.toFixed(2);
  };

  // Determine color based on change
  const getChangeColor = (changePercent?: number): string => {
    if (!changePercent) return 'var(--ggui-color-onSurfaceVariant)';
    return changePercent > 0 ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  };

  // Get border color based on change
  const getChangeBorderColor = (changePercent?: number): string => {
    if (!changePercent) return 'var(--ggui-color-outline)';
    return changePercent > 0 ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
  };

  // Get arrow symbol
  const getArrow = (changePercent?: number): string => {
    if (!changePercent) return '−';
    return changePercent > 0 ? '▲' : '▼';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title and timestamp */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated:
            </Text>
            <Text variant="label" color="var(--ggui-color-onSurface)">
              {lastUpdatedTime}
            </Text>
          </Row>
        </Stack>

        {/* Market status indicator */}
        {marketStatus.latest && (
          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-primary-50)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Text variant="bodySmall" color="var(--ggui-color-primary-700)">
              Market Status:{' '}
              <Text variant="label" is="span">
                {marketStatus.latest.status
                  ?.replace('-', ' ')
                  .toUpperCase() || 'UNKNOWN'}
              </Text>
            </Text>
          </Box>
        )}

        {/* Stock cards grid */}
        <div className="stock-grid">
          {displayedStocks.map((stock) => {
            const isFlashing = flashingSymbols.has(stock.symbol || '');
            const changeColor = getChangeColor(stock.changePercent);
            const borderColor = getChangeBorderColor(stock.changePercent);
            const arrow = getArrow(stock.changePercent);

            return (
              <Card
                key={stock.symbol || 'unknown'}
                padding="var(--ggui-spacing-4)"
                shadow="md"
                border={true}
                radius="lg"
                style={{
                  borderColor: borderColor,
                  borderWidth: '2px',
                  borderStyle: 'solid',
                }}
                className={isFlashing ? 'stock-card-flash' : ''}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Ticker symbol - large and bold */}
                  <Text
                    variant="body"
                    weight="bold"
                    size="3xl"
                    color="var(--ggui-color-onSurface)"
                  >
                    {stock.symbol || 'N/A'}
                  </Text>

                  {/* Company name */}
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant)"
                  >
                    {stock.name || 'Unknown Company'}
                  </Text>

                  {/* Current price */}
                  <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                    <Text variant="body" weight="medium" size="2xl" color="var(--ggui-color-onSurface)">
                      ${formatPrice(stock.price)}
                    </Text>
                  </Stack>

                  {/* Change amount and percentage */}
                  <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                    <Text variant="label" color={changeColor}>
                      {stock.change !== undefined && stock.change !== null
                        ? (stock.change > 0 ? '+' : '') + stock.change.toFixed(2)
                        : 'N/A'}
                    </Text>
                    <Text variant="label" color={changeColor}>
                      {arrow}
                    </Text>
                    <Badge
                      variant={stock.changePercent && stock.changePercent > 0 ? 'success' : 'error'}
                      size="sm"
                    >
                      {stock.changePercent !== undefined && stock.changePercent !== null
                        ? (stock.changePercent > 0 ? '+' : '') + stock.changePercent.toFixed(2) + '%'
                        : 'N/A'}
                    </Badge>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>

        {/* Empty state */}
        {displayedStocks.length === 0 && (
          <Card padding="var(--ggui-spacing-6)" shadow="sm">
            <Stack gap="var(--ggui-spacing-3)" align="center" justify="center">
              <Icon name="trending-up" size={48} color="var(--ggui-color-onSurfaceVariant)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
                No stocks to display. Add stocks to get started.
              </Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State management for the wizard
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions[0] || ''),
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications !== undefined ? props.initialProfile.emailNotifications : true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Email validation helper
  const isValidEmail = useCallback((email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }, []);

  // Validate current step
  const validateStep = useCallback((step: number): boolean => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
      }
      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!isValidEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email address';
      }
    }

    if (step === 2) {
      if (!formData.role) {
        newErrors.role = 'Please select a role';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [formData, isValidEmail]);

  // Handle next button
  const handleNext = useCallback(() => {
    if (validateStep(currentStep)) {
      setCurrentStep(currentStep + 1);
      setErrors({});
    }
  }, [currentStep, validateStep]);

  // Handle back button
  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({});
    }
  }, [currentStep]);

  // Handle complete
  const handleComplete = useCallback(() => {
    if (validateStep(currentStep)) {
      complete(formData);
    }
  }, [currentStep, formData, validateStep, complete]);

  // Compute next button disabled state
  const isNextDisabled = useMemo(() => {
    if (currentStep === 1) {
      return !formData.name.trim() || !formData.email.trim() || !isValidEmail(formData.email);
    }
    if (currentStep === 2) {
      return !formData.role;
    }
    return false;
  }, [currentStep, formData, isValidEmail]);

  // Role options as SelectOption array
  const roleSelectOptions = useMemo(() => 
    props.roleOptions.map(role => ({ value: role, label: role })),
    [props.roleOptions]
  );

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Step Indicator */}
        <Stack gap="var(--ggui-spacing-4)" align="center" style={{ width: '100%', maxWidth: '600px' }}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 3
          </Text>
          <Progress value={currentStep} max={3} size="md" />
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={2}>Profile Setup</Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  Tell us about yourself to get started
                </Text>
              </Stack>

              {/* Name Input */}
              <Input
                label="Name"
                placeholder="Enter your full name"
                value={formData.name}
                onChange={(value) => {
                  setFormData({ ...formData, name: value });
                  if (errors.name) setErrors({ ...errors, name: '' });
                }}
                error={errors.name}
                required
              />

              {/* Email Input */}
              <Input
                label="Email"
                type="email"
                placeholder="you@example.com"
                value={formData.email}
                onChange={(value) => {
                  setFormData({ ...formData, email: value });
                  if (errors.email) setErrors({ ...errors, email: '' });
                }}
                error={errors.email}
                required
              />

              {/* Avatar Selection */}
              <Stack gap="var(--ggui-spacing-3)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Avatar
                </Text>
                <Row gap="var(--ggui-spacing-3)" wrap align="center">
                  {props.avatarOptions.map((avatarOption) => (
                    <Box
                      key={avatarOption}
                      as={Clickable}
                      onClick={() => setFormData({ ...formData, avatar: avatarOption })}
                      padding="var(--ggui-spacing-2)"
                      borderRadius="var(--ggui-shape-radius-lg)"
                      background={
                        formData.avatar === avatarOption
                          ? 'var(--ggui-color-primary-100)'
                          : 'transparent'
                      }
                      style={{
                        border:
                          formData.avatar === avatarOption
                            ? '2px solid var(--ggui-color-primary-600)'
                            : '2px solid var(--ggui-color-outline)',
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                      }}
                      hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                    >
                      <Text size="3xl">{avatarOption}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={2}>Preferences</Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  Customize your experience
                </Text>
              </Stack>

              {/* Role Selection */}
              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => {
                  setFormData({ ...formData, role: value });
                  if (errors.role) setErrors({ ...errors, role: '' });
                }}
                options={roleSelectOptions}
                placeholder="Select your role"
                error={errors.role}
                required
              />

              {/* Email Notifications Toggle */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurface)">
                  Notifications
                </Text>
                <Toggle
                  label="Enable email notifications"
                  checked={formData.emailNotifications}
                  onChange={(checked) => setFormData({ ...formData, emailNotifications: checked })}
                  size="md"
                />
              </Stack>

              {/* Theme Preference Toggle */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurface)">
                  Theme
                </Text>
                <Toggle
                  label={formData.theme === 'dark' ? 'Dark mode' : 'Light mode'}
                  checked={formData.theme === 'dark'}
                  onChange={(checked) => setFormData({ ...formData, theme: checked ? 'dark' : 'light' })}
                  size="md"
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" style={{ width: '100%', maxWidth: '600px' }}>
            <Stack gap="var(--ggui-spacing-6)">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={2}>Review & Confirm</Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  Please review your information before completing setup
                </Text>
              </Stack>

              {/* Summary Section */}
              <Stack gap="var(--ggui-spacing-4)" style={{ width: '100%' }}>
                {/* Profile Summary */}
                <Stack gap="var(--ggui-spacing-3)" style={{ width: '100%' }}>
                  <Text variant="label" color="var(--ggui-color-onSurface)" weight="semibold">
                    Profile
                  </Text>
                  <Row justify="between" align="center" style={{ width: '100%' }}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      Name:
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface)" weight="medium">
                      {formData.name}
                    </Text>
                  </Row>
                  <Row justify="between" align="center" style={{ width: '100%' }}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      Email:
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface)" weight="medium">
                      {formData.email}
                    </Text>
                  </Row>
                  <Row justify="between" align="center" style={{ width: '100%' }}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      Avatar:
                    </Text>
                     <Text size="3xl">{formData.avatar}</Text>
                  </Row>
                </Stack>

                <Divider orientation="horizontal" margin="var(--ggui-spacing-3)" />

                {/* Preferences Summary */}
                <Stack gap="var(--ggui-spacing-3)" style={{ width: '100%' }}>
                  <Text variant="label" color="var(--ggui-color-onSurface)" weight="semibold">
                    Preferences
                  </Text>
                  <Row justify="between" align="center" style={{ width: '100%' }}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      Role:
                    </Text>
                    <Badge variant="primary" size="sm">
                      {formData.role}
                    </Badge>
                  </Row>
                  <Row justify="between" align="center" style={{ width: '100%' }}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      Email Notifications:
                    </Text>
                    <Badge variant={formData.emailNotifications ? 'success' : 'secondary'} size="sm">
                      {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                    </Badge>
                  </Row>
                  <Row justify="between" align="center" style={{ width: '100%' }}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      Theme:
                    </Text>
                    <Badge variant="secondary" size="sm">
                      {formData.theme.charAt(0).toUpperCase() + formData.theme.slice(1)}
                    </Badge>
                  </Row>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="center" style={{ width: '100%', maxWidth: '600px' }}>
          {currentStep > 1 && (
            <Button variant="outline" onClick={handleBack}>
              Back
            </Button>
          )}
          {currentStep < 3 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={isNextDisabled}
            >
              Next
            </Button>
          )}
          {currentStep === 3 && (
            <Button
              variant="primary"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
